# Category: race_condition

def process_transactions(transactions, accounts):
    """
    Processes a list of financial transactions and updates account balances.

    Parameters:
    transactions (list): A list of transaction dictionaries with keys:
                         'from_account', 'to_account', 'amount'
    accounts (dict): A dictionary with account names as keys and balances as values.

    Returns:
    dict: Updated account balances.
    """
    for tx in transactions:
        from_acc = tx.get('from_account')
        to_acc = tx.get('to_account')
        amount = tx.get('amount', 0)

        if from_acc not in accounts or to_acc not in accounts:
            continue  # Skip invalid accounts

        if accounts[from_acc] >= amount:
            accounts[from_acc] -= amount
            accounts[to_acc] += amount
        else:
            continue  # Skip transaction if insufficient funds

    return accounts

